sql:
SELECT DISTINCT team_name
FROM teams
WHERE conference = 'Pacific';

SELECT 
  (SELECT overall_record FROM standings WHERE team_id = 1 AND last_updated BETWEEN '2020-01-01' AND '2022-12-31') AS overall_record,
  (SELECT AVG(attendance) FROM games WHERE team_id = 1) AS average_attendance;

external_knowledge:
Eastern teams: Teams belonging to the Eastern conference; 
Victorious: Refers to teams having won their games; 
Couple of years: Refers to the period from 2022 to 2023 as specified in the SQL query.
